import React, { useState, useCallback, useMemo } from "react";
import {
  Box,
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TablePagination,
  Typography,
  Checkbox,
  useTheme,
  alpha,
  CircularProgress,
} from "@mui/material";
import { motion } from "motion/react";
import { LuArrowUpDown, LuChevronDown } from "react-icons/lu";

const MotionTableRow = motion.create(TableRow);
const MotionPaper = motion.create(Paper);

// Sample data
const createData = (id, name, role, status, progress, date) => ({
  id,
  name,
  role,
  status,
  progress,
  date,
  details: {
    email: `${name.toLowerCase().replace(" ", ".")}@example.com`,
    phone: "+1 (555) 000-0000",
    // ... more details
  },
});

const sampleData = [
  createData(1, "Alex Thompson", "Developer", "Active", 75, "2025-01-01"),
  // ... more data
];

const ModernTable = () => {
  const theme = useTheme();
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(5);
  const [selected, setSelected] = useState([]);
  const [sortConfig, setSortConfig] = useState({ key: null, direction: "asc" });

  const sortedData = useMemo(() => {
    if (!sortConfig.key) return sampleData;
    return [...sampleData].sort((a, b) => {
      const aVal = a[sortConfig.key];
      const bVal = b[sortConfig.key];
      if (typeof aVal === "string") {
        return sortConfig.direction === "asc"
          ? aVal.localeCompare(bVal)
          : bVal.localeCompare(aVal);
      }
      return sortConfig.direction === "asc" ? aVal - bVal : bVal - aVal;
    });
  }, [sortConfig]);

  const handleSort = (key) => {
    setSortConfig((current) => ({
      key,
      direction: current.key === key && current.direction === "asc" ? "desc" : "asc",
    }));
  };

  const handleSelectAllClick = useCallback((event) => {
    setSelected(event.target.checked ? sampleData.map((row) => row.id) : []);
  }, []);

  const handleSelectClick = useCallback((id) => {
    setSelected((prev) => {
      const selectedIndex = prev.indexOf(id);
      if (selectedIndex === -1) return [...prev, id];
      return prev.filter((itemId) => itemId !== id);
    });
  }, []);

  const StatusBadge = ({ status }) => (
    <Box
      component={motion.div}
      initial={{ scale: 0.8, opacity: 0 }}
      animate={{ scale: 1, opacity: 1 }}
      transition={{ duration: 0.3, ease: "easeOut" }}
      sx={{
        display: "inline-flex",
        px: 1.5,
        py: 0.75,
        borderRadius: 2,
        bgcolor: status === "Active"
          ? alpha(theme.palette.success.main, 0.1)
          : alpha(theme.palette.error.main, 0.1),
        color: status === "Active"
          ? theme.palette.success.main
          : theme.palette.error.main,
        fontWeight: 500,
      }}
    >
      {status}
    </Box>
  );

  const ProgressBar = ({ value, delay = 0 }) => (
    <Box sx={{ display: "flex", alignItems: "center", gap: 1 }}>
      <Box
        sx={{
          flexGrow: 1,
          bgcolor: alpha(theme.palette.primary.main, 0.1),
          borderRadius: 1,
          overflow: "hidden",
        }}
      >
        <Box
          component={motion.div}
          initial={{ width: 0 }}
          animate={{ width: `${value}%` }}
          transition={{ duration: 0.8, delay, ease: "easeOut" }}
          sx={{
            height: 6,
            bgcolor: theme.palette.primary.main,
            borderRadius: 1,
          }}
        />
      </Box>
      <Typography variant="body2" color="text.secondary" sx={{ minWidth: 40 }}>
        {value}%
      </Typography>
    </Box>
  );

  return (
    <MotionPaper
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.3, ease: "easeOut" }}
      sx={{
        overflow: "hidden",
        bgcolor: "background.paper",
        border: `1px solid ${theme.palette.divider}`,
        boxShadow: "0 4px 20px rgba(0, 0, 0, 0.1)",
        borderRadius: 2,
      }}
    >
      <TableContainer>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell padding="checkbox">
                <Checkbox
                  indeterminate={selected.length > 0 && selected.length < sampleData.length}
                  checked={selected.length === sampleData.length}
                  onChange={handleSelectAllClick}
                />
              </TableCell>
              {[
                { key: "name", label: "Name" },
                { key: "role", label: "Role" },
                { key: "status", label: "Status" },
                { key: "progress", label: "Progress" },
                { key: "date", label: "Date" },
              ].map((header) => (
                <TableCell key={header.key}>
                  <Box
                    sx={{
                      display: "flex",
                      alignItems: "center",
                      gap: 0.5,
                      cursor: "pointer",
                      "&:hover": { color: theme.palette.primary.main },
                    }}
                    onClick={() => handleSort(header.key)}
                  >
                    {header.label}
                    <Box
                      component={motion.div}
                      animate={{
                        rotate: sortConfig.key === header.key
                          ? sortConfig.direction === "desc" ? 180 : 0
                          : 0,
                      }}
                      transition={{ duration: 0.3, ease: "easeOut" }}
                    >
                      <LuArrowUpDown size={16} />
                    </Box>
                  </Box>
                </TableCell>
              ))}
            </TableRow>
          </TableHead>
          <TableBody>
            {sortedData
              .slice(page * rowsPerPage, page * rowsPerPage + rowsPerPage)
              .map((row, index) => {
                const isSelected = selected.indexOf(row.id) !== -1;
                return (
                  <MotionTableRow
                    key={row.id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{
                      delay: index * 0.05,
                      duration: 0.3,
                      ease: "easeOut",
                    }}
                    sx={{
                      bgcolor: isSelected
                        ? alpha(theme.palette.primary.main, 0.08)
                        : "transparent",
                      "&:hover": {
                        bgcolor: isSelected
                          ? alpha(theme.palette.primary.main, 0.12)
                          : alpha(theme.palette.primary.main, 0.04),
                      },
                    }}
                  >
                    <TableCell padding="checkbox">
                      <Checkbox
                        checked={isSelected}
                        onChange={() => handleSelectClick(row.id)}
                      />
                    </TableCell>
                    <TableCell>
                      <Typography variant="subtitle2">{row.name}</Typography>
                      <Typography variant="body2" color="text.secondary">
                        {row.details.email}
                      </Typography>
                    </TableCell>
                    <TableCell>{row.role}</TableCell>
                    <TableCell>
                      <StatusBadge status={row.status} />
                    </TableCell>
                    <TableCell>
                      <ProgressBar value={row.progress} delay={index * 0.05} />
                    </TableCell>
                    <TableCell>{row.date}</TableCell>
                  </MotionTableRow>
                );
              })}
          </TableBody>
        </Table>
      </TableContainer>
      <TablePagination
        component="div"
        count={sampleData.length}
        page={page}
        rowsPerPage={rowsPerPage}
        onPageChange={(e, newPage) => setPage(newPage)}
        rowsPerPageOptions={[5, 10, 15, 25]}
        onRowsPerPageChange={(e) => {
          setRowsPerPage(parseInt(e.target.value, 10));
          setPage(0);
        }}
        SelectProps={{
          IconComponent: LuChevronDown,
          sx: { fontSize: "16px !important" },
        }}
      />
    </MotionPaper>
  );
};

export default ModernTable;

