import React, { useState } from "react";
import {
  Box,
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TablePagination,
  Typography,
  IconButton,
  Tooltip,
  Collapse,
  useTheme,
  alpha,
} from "@mui/material";
import { motion } from "motion/react";
import { LuChevronDown, LuSearch, LuFilter } from "react-icons/lu";

const MotionTableRow = motion.create(TableRow);
const MotionPaper = motion.create(Paper);

const ExpandableTable = () => {
  const theme = useTheme();
  const [page, setPage] = useState(0);
  const [rowsPerPage, setRowsPerPage] = useState(5);
  const [expandedRow, setExpandedRow] = useState(null);

  const StatusBadge = ({ status }) => (
    <Box
      component={motion.div}
      initial={{ scale: 0.8, opacity: 0 }}
      animate={{ scale: 1, opacity: 1 }}
      transition={{ duration: 0.3, ease: "easeOut" }}
      sx={{
        display: "inline-flex",
        px: 1.5,
        py: 0.75,
        borderRadius: 2,
        bgcolor: status === "Active"
          ? alpha(theme.palette.success.main, 0.1)
          : alpha(theme.palette.error.main, 0.1),
        color: status === "Active"
          ? theme.palette.success.main
          : theme.palette.error.main,
        fontWeight: 500,
      }}
    >
      {status}
    </Box>
  );

  return (
    <MotionPaper
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      transition={{ duration: 0.3, ease: "easeOut" }}
      sx={{
        overflow: "hidden",
        bgcolor: "background.paper",
        border: `1px solid ${theme.palette.divider}`,
        boxShadow: "0 4px 20px rgba(0, 0, 0, 0.1)",
        borderRadius: 2,
      }}
    >
      <TableContainer>
        <Table>
          <TableHead>
            <TableRow>
              <TableCell padding="checkbox" />
              <TableCell>Name</TableCell>
              <TableCell>Role</TableCell>
              <TableCell>Status</TableCell>
              <TableCell>Date</TableCell>
              <TableCell align="right">Actions</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {sampleData
              .slice(page * rowsPerPage, page * rowsPerPage + rowsPerPage)
              .map((row, index) => (
                <React.Fragment key={row.id}>
                  <MotionTableRow
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{
                      delay: index * 0.05,
                      duration: 0.3,
                      ease: "easeOut",
                    }}
                    sx={{
                      "&:hover": {
                        bgcolor: alpha(theme.palette.primary.main, 0.04),
                      },
                    }}
                  >
                    <TableCell padding="checkbox">
                      <IconButton
                        size="small"
                        onClick={() =>
                          setExpandedRow(expandedRow === row.id ? null : row.id)
                        }
                        sx={{
                          transition: "transform 0.2s",
                          transform: expandedRow === row.id ? "rotate(-180deg)" : "none",
                        }}
                      >
                        <LuChevronDown />
                      </IconButton>
                    </TableCell>
                    <TableCell>
                      <Typography variant="subtitle2">{row.name}</Typography>
                      <Typography variant="body2" color="text.secondary">
                        {row.details.email}
                      </Typography>
                    </TableCell>
                    <TableCell>{row.role}</TableCell>
                    <TableCell>
                      <StatusBadge status={row.status} />
                    </TableCell>
                    <TableCell>{row.date}</TableCell>
                    <TableCell align="right">
                      <Box sx={{ display: "flex", gap: 1, justifyContent: "flex-end" }}>
                        <Tooltip arrow title="View Details">
                          <IconButton size="small">
                            <LuSearch />
                          </IconButton>
                        </Tooltip>
                        <Tooltip arrow title="Filter">
                          <IconButton size="small">
                            <LuFilter />
                          </IconButton>
                        </Tooltip>
                      </Box>
                    </TableCell>
                  </MotionTableRow>
                  <TableRow>
                    <TableCell colSpan={6} sx={{ p: 0, border: 0 }}>
                      <Collapse in={expandedRow === row.id} timeout="auto" unmountOnExit>
                        <Box sx={{ p: 3, bgcolor: alpha(theme.palette.primary.main, 0.04) }}>
                          <Typography variant="h6" gutterBottom>
                            Additional Details
                          </Typography>
                          <Box
                            sx={{
                              display: "grid",
                              gridTemplateColumns: {
                                xs: "1fr",
                                sm: "repeat(2, 1fr)",
                                md: "repeat(3, 1fr)",
                              },
                              gap: 3,
                            }}
                          >
                            {Object.entries(row.details).map(([key, value]) => (
                              <Box key={key}>
                                <Typography variant="subtitle2" color="text.secondary">
                                  {key.charAt(0).toUpperCase() + key.slice(1)}
                                </Typography>
                                <Typography>
                                  {Array.isArray(value) ? value.join(", ") : value}
                                </Typography>
                              </Box>
                            ))}
                          </Box>
                        </Box>
                      </Collapse>
                    </TableCell>
                  </TableRow>
                </React.Fragment>
              ))}
          </TableBody>
        </Table>
      </TableContainer>
      <TablePagination
        component="div"
        count={sampleData.length}
        page={page}
        rowsPerPage={rowsPerPage}
        onPageChange={(e, newPage) => setPage(newPage)}
        rowsPerPageOptions={[5, 10, 15, 25]}
        onRowsPerPageChange={(e) => {
          setRowsPerPage(parseInt(e.target.value, 10));
          setPage(0);
        }}
      />
    </MotionPaper>
  );
};

export default ExpandableTable;
